def find_log_entry(logs, target):
    for i in range(len(logs)):
        if logs[i] == target:
            return i
    return -1

unit_tests:
import unittest

class TestSolution(unittest.TestCase):
    def test_found_in_middle(self):
        self.assertEqual(find_log_entry([450, 500, 600, 100, 200, 300], 200), 4)

    def test_not_found(self):
        self.assertEqual(find_log_entry([450, 500, 600, 100, 200, 300], 999), -1)

    def test_found_at_rotation_point(self):
        self.assertEqual(find_log_entry([30, 40, 50, 10, 20], 10), 3)

    def test_hidden_empty_list(self):
        self.assertEqual(find_log_entry([], 5), -1)

    def test_hidden_single_element_found(self):
        self.assertEqual(find_log_entry([42], 42), 0)

    def test_hidden_single_element_not_found(self):
        self.assertEqual(find_log_entry([42], 7), -1)

    def test_hidden_no_rotation(self):
        self.assertEqual(find_log_entry([1, 2, 3, 4, 5], 3), 2)

    def test_hidden_target_at_first_index(self):
        self.assertEqual(find_log_entry([400, 500, 100, 200, 300], 400), 0)

    def test_hidden_target_at_last_index(self):
        self.assertEqual(find_log_entry([400, 500, 100, 200, 300], 300), 4)

    def test_hidden_large_rotation(self):
        logs = list(range(500, 1000)) + list(range(0, 500))
        self.assertEqual(find_log_entry(logs, 0), 500)
        self.assertEqual(find_log_entry(logs, 999), 499)
        self.assertEqual(find_log_entry(logs, 1500), -1)

    def test_hidden_two_elements(self):
        self.assertEqual(find_log_entry([20, 10], 10), 1)
        self.assertEqual(find_log_entry([20, 10], 20), 0)

if __name__ == '__main__':
    unittest.main()
